import React, { useEffect, useState } from 'react';
import {
  View,
  Text,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
  Platform,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const AUTH_FLAG_KEY = 'AUTHENTICATED';
const rnBiometrics = new ReactNativeBiometrics();

const App = () => {
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState(null);
  const [password, setPassword] = useState('');

  useEffect(() => {
    bootstrapAuth();
  }, []);

  const bootstrapAuth = async () => {
    try {
      const savedAuth = await AsyncStorage.getItem(AUTH_FLAG_KEY);
      if (savedAuth === 'true') {
        setIsAuthenticated(true);
        setLoading(false);
        return;
      }

      const { available, biometryType } = await rnBiometrics.isSensorAvailable();

      if (available) {
        setBiometricAvailable(true);
        setBiometricType(biometryType);
        const success = await authenticateWithBiometrics(biometryType);
        if (success) {
          await persistAuthenticated();
        }
      } else {
        setBiometricAvailable(false);
      }
    } catch (error) {
      setBiometricAvailable(false);
    } finally {
      setLoading(false);
    }
  };

  const authenticateWithBiometrics = async (type) => {
    try {
      const promptMessage =
        type === ReactNativeBiometrics.FaceID
          ? 'Authenticate with Face ID'
          : type === ReactNativeBiometrics.TouchID
          ? 'Authenticate with Touch ID'
          : 'Authenticate with Biometrics';

      const { success } = await rnBiometrics.simplePrompt({
        promptMessage,
        cancelButtonText: 'Use Password',
      });

      return success;
    } catch (error) {
      return false;
    }
  };

  const persistAuthenticated = async () => {
    await AsyncStorage.setItem(AUTH_FLAG_KEY, 'true');
    setIsAuthenticated(true);
  };

  const handlePasswordLogin = async () => {
    if (!password.trim()) {
      Alert.alert('Error', 'Please enter your password');
      return;
    }

    if (password === 'password123') {
      await persistAuthenticated();
      setPassword('');
    } else {
      Alert.alert('Login Failed', 'Invalid password');
    }
  };

  const handleBiometricLogin = async () => {
    const success = await authenticateWithBiometrics(biometricType);
    if (success) {
      await persistAuthenticated();
    } else {
      Alert.alert('Authentication Failed', 'Biometric verification was not successful');
    }
  };

  const handleLogout = async () => {
    await AsyncStorage.removeItem(AUTH_FLAG_KEY);
    setIsAuthenticated(false);
    setPassword('');
    bootstrapAuth();
  };

  const biometricLabel = () => {
    if (biometricType === ReactNativeBiometrics.FaceID) return 'Face ID';
    if (biometricType === ReactNativeBiometrics.TouchID) return 'Touch ID';
    if (Platform.OS === 'android') return 'Fingerprint';
    return 'Biometrics';
  };

  if (loading) {
    return (
      <View style={styles.center}>
        <ActivityIndicator size="large" />
        <Text style={styles.loadingText}>Checking authentication...</Text>
      </View>
    );
  }

  if (isAuthenticated) {
    return (
      <View style={styles.container}>
        <Text style={styles.title}>Home Screen</Text>
        <Text style={styles.subtitle}>You are authenticated.</Text>
        <TouchableOpacity style={styles.button} onPress={handleLogout}>
          <Text style={styles.buttonText}>Logout</Text>
        </TouchableOpacity>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>

      {biometricAvailable ? (
        <>
          <Text style={styles.subtitle}>Use {biometricLabel()} to continue</Text>
          <TouchableOpacity style={styles.button} onPress={handleBiometricLogin}>
            <Text style={styles.buttonText}>Login with {biometricLabel()}</Text>
          </TouchableOpacity>
          <Text style={styles.orText}>or use password</Text>
        </>
      ) : (
        <Text style={styles.subtitle}>Biometrics not available. Use password to continue.</Text>
      )}

      <TextInput
        style={styles.input}
        placeholder="Enter password"
        secureTextEntry
        value={password}
        onChangeText={setPassword}
      />

      <TouchableOpacity style={styles.buttonSecondary} onPress={handlePasswordLogin}>
        <Text style={styles.buttonText}>Login with Password</Text>
      </TouchableOpacity>
    </View>
  );
};

